import React, { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import './Login.css';

function Login() {
  const [formData, setFormData] = useState({ email: '', password: '' });
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate(); // To perform redirection action

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleSubmit = (e) => {
    e.preventDefault(); // Prevents page refresh
    setLoading(true);

    console.log("Login Action Triggered:", formData);

    // ACTION 1: Show a success message
    alert("Login Successful! Welcome to FreelanceHub.");

    // ACTION 2: Store email in LocalStorage for session persistence
    localStorage.setItem("userEmail", formData.email);

    // ACTION 3: Redirect to Client Dashboard
    setTimeout(() => {
        setLoading(false);
        navigate('/client-dashboard'); 
    }, 1000);
  };

  return (
    <div className="login-container">
      <div className="card shadow login-card">
        <h2 className="text-center fw-bold mb-4">Login</h2>
        
        <form onSubmit={handleSubmit}>
          <div className="mb-3">
            <label className="form-label fw-semibold">Email Address</label>
            <input 
              type="email" 
              name="email" 
              className="form-control form-control-sm" 
              placeholder="Enter your email"
              onChange={handleChange} 
              required 
            />
          </div>

          <div className="mb-3">
            <label className="form-label fw-semibold">Password</label>
            <input 
              type="password" 
              name="password" 
              className="form-control form-control-sm" 
              placeholder="Enter your password"
              onChange={handleChange} 
              required 
            />
          </div>

          {/* LOGIN BUTTON ACTION */}
          <button 
            type="submit" 
            className="btn btn-primary w-100 btn-sm shadow-sm mt-3 fw-bold"
            disabled={loading}
          >
            {loading ? "Logging in..." : "Login Now"}
          </button>
        </form>

        <p className="text-center mt-4 small text-muted">
          Don't have an account? <Link to="/register" className="text-primary fw-bold">Sign Up</Link>
        </p>
      </div>
    </div>
  );
}

export default Login;
